@Composable
fun ClientListRoute(
    onAddClient: () -> Unit,
    onEditClient: (Long) -> Unit,
    onBack: () -> Unit,
    modifier: Modifier = Modifier
) {
    val application = LocalContext.current.applicationContext as ProPaintersApplication
    val viewModel: ClientListViewModel = viewModel(
        factory = ClientListViewModel.provideFactory(application.container.clientRepository)
    )
    val uiState by viewModel.uiState.collectAsState()

    ClientListScreen(
        clients = uiState.clients,
        searchQuery = uiState.searchQuery,
        onSearchQueryChange = viewModel::onSearchQueryChange,
        onAddClient = onAddClient,
        onEditClient = onEditClient,
        onDeleteClient = viewModel::deleteClient,
        onBack = onBack,
        modifier = modifier
    )
}

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun ClientListScreen(
    clients: List<ClientEntity>,
    searchQuery: String,
    onSearchQueryChange: (String) -> Unit,
    onAddClient: () -> Unit,
    onEditClient: (Long) -> Unit,
    onDeleteClient: (ClientEntity) -> Unit,
    onBack: () -> Unit,
    modifier: Modifier = Modifier
) {
    Scaffold(
        modifier = modifier.fillMaxSize(),
        topBar = {
            TopAppBar(
                title = { Text("Clients") },
                navigationIcon = {
                    IconButton(onClick = onBack) {
                        Icon(Icons.AutoMirrored.Filled.ArrowBack, contentDescription = "Back")
                    }
                }
            )
        },
        floatingActionButton = {
            FloatingActionButton(onClick = onAddClient) {
                Icon(Icons.Default.Add, contentDescription = "Add Client")
            }
        }
    ) { innerPadding ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(innerPadding)
        ) {
            OutlinedTextField(
                value = searchQuery,
                onValueChange = onSearchQueryChange,
                label = { Text("Search clients") },
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(horizontal = 16.dp, vertical = 8.dp),
                singleLine = true
            )

            if (clients.isEmpty()) {
                Column(
                    modifier = Modifier
                        .fillMaxSize()
                        .padding(24.dp),
                    horizontalAlignment = Alignment.CenterHorizontally,
                    verticalArrangement = Arrangement.Center
                ) {
                    Text(
                        text = if (searchQuery.isBlank()) "No clients yet" else "No clients match your search",
                        style = MaterialTheme.typography.titleMedium
                    )
                    Text(
                        text = if (searchQuery.isBlank()) "Tap + to add your first client" else "Try a different search term",
                        style = MaterialTheme.typography.bodyMedium,
                        modifier = Modifier.padding(top = 8.dp)
                    )
                }
            } else {
                LazyColumn(
                    modifier = Modifier.fillMaxSize(),
                    verticalArrangement = Arrangement.spacedBy(8.dp),
                    contentPadding = androidx.compose.foundation.layout.PaddingValues(
                        horizontal = 16.dp, vertical = 8.dp
                    )
                ) {
                    items(clients, key = { it.clientId }) { client ->
                        ClientCard(
                            client = client,
                            onEdit = { onEditClient(client.clientId) },
                            onDelete = { onDeleteClient(client) }
                        )
                    }
                }
            }
        }
    }
}

@Composable
private fun ClientCard(
    client: ClientEntity,
    onEdit: () -> Unit,
    onDelete: () -> Unit
) {
    Card(
        modifier = Modifier
            .fillMaxWidth()
            .clickable(onClick = onEdit)
    ) {
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .padding(12.dp),
            verticalAlignment = Alignment.CenterVertically,
            horizontalArrangement = Arrangement.spacedBy(12.dp)
        ) {
            Icon(
                imageVector = if (client.clientType == "BUSINESS") Icons.Default.Business else Icons.Default.Person,
                contentDescription = client.clientType,
                tint = MaterialTheme.colorScheme.primary
            )
            Column(modifier = Modifier.weight(1f)) {
                Text(
                    text = client.name,
                    style = MaterialTheme.typography.titleSmall,
                    fontWeight = FontWeight.Bold
                )
                if (client.phoneNumber.isNotBlank()) {
                    Text(text = client.phoneNumber, style = MaterialTheme.typography.bodySmall)
                }
                if (client.email.isNotBlank()) {
                    Text(text = client.email, style = MaterialTheme.typography.bodySmall)
                }
                Text(
                    text = if (client.clientType == "BUSINESS") "Business" else "Private",
                    style = MaterialTheme.typography.labelSmall,
                    color = MaterialTheme.colorScheme.outline
                )
            }
            IconButton(onClick = onDelete) {
                Icon(
                    Icons.Default.Delete,
                    contentDescription = "Delete",
                    tint = MaterialTheme.colorScheme.error
                )
            }
        }
    }
}

package com.example.propaintersplastererspayment.feature.client.vm

import androidx.lifecycle.ViewModel
import androidx.lifecycle.ViewModelProvider
import androidx.lifecycle.viewModelScope
import com.example.propaintersplastererspayment.data.local.entity.ClientEntity
import com.example.propaintersplastererspayment.domain.repository.ClientRepository
import kotlinx.coroutines.flow.MutableSharedFlow
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.SharedFlow
import kotlinx.coroutines.flow.SharingStarted
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asSharedFlow
import kotlinx.coroutines.flow.combine
import kotlinx.coroutines.flow.stateIn
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch

data class ClientFormState(
    val name: String = "",
    val clientType: String = "PRIVATE",   // "PRIVATE" or "BUSINESS"
    val address: String = "",
    val phoneNumber: String = "",
    val email: String = "",
    val notes: String = "",
    val errorMessage: String? = null
) {
    val isValid: Boolean get() = name.isNotBlank()
}

data class AddEditClientUiState(
    val formState: ClientFormState = ClientFormState(),
    val isLoading: Boolean = false,
    val isSaving: Boolean = false,
    val isExistingClient: Boolean = false,
    val userMessage: String? = null
)

class AddEditClientViewModel(
    private val clientId: Long?,
    private val clientRepository: ClientRepository
) : ViewModel() {

    private val formState = MutableStateFlow(ClientFormState())
    private val isSaving = MutableStateFlow(false)
    private val userMessage = MutableStateFlow<String?>(null)
    private val isExistingClient = MutableStateFlow(false)

    private val _savedEvent = MutableSharedFlow<Unit>()
    val savedEvent: SharedFlow<Unit> = _savedEvent.asSharedFlow()

    val uiState: StateFlow<AddEditClientUiState> = combine(
        formState, isSaving, userMessage, isExistingClient
    ) { form, saving, message, existing ->
        AddEditClientUiState(
            formState = form,
            isSaving = saving,
            isExistingClient = existing,
            userMessage = message
        )
    }.stateIn(
        scope = viewModelScope,
        started = SharingStarted.WhileSubscribed(5_000),
        initialValue = AddEditClientUiState()
    )

    init {
        if (clientId != null && clientId > 0L) {
            viewModelScope.launch {
                val client = clientRepository.getClient(clientId)
                if (client != null) {
                    isExistingClient.value = true
                    formState.value = ClientFormState(
                        name = client.name,
                        clientType = client.clientType,
                        address = client.address,
                        phoneNumber = client.phoneNumber,
                        email = client.email,
                        notes = client.notes
                    )
                }
            }
        }
    }

    fun onNameChange(value: String) = formState.update { it.copy(name = value, errorMessage = null) }
    fun onClientTypeChange(value: String) = formState.update { it.copy(clientType = value) }
    fun onAddressChange(value: String) = formState.update { it.copy(address = value) }
    fun onPhoneChange(value: String) = formState.update { it.copy(phoneNumber = value) }
    fun onEmailChange(value: String) = formState.update { it.copy(email = value) }
    fun onNotesChange(value: String) = formState.update { it.copy(notes = value) }

    fun saveClient() {
        val form = formState.value
        if (form.name.isBlank()) {
            formState.update { it.copy(errorMessage = "Name is required.") }
            return
        }
        isSaving.value = true
        viewModelScope.launch {
            try {
                clientRepository.saveClient(
                    ClientEntity(
                        clientId = clientId ?: 0L,
                        name = form.name.trim(),
                        clientType = form.clientType,
                        address = form.address.trim(),
                        phoneNumber = form.phoneNumber.trim(),
                        email = form.email.trim(),
                        notes = form.notes.trim()
                    )
                )
                _savedEvent.emit(Unit)
            } catch (e: Exception) {
                userMessage.value = "Error saving client: ${e.message}"
            } finally {
                isSaving.value = false
            }
        }
    }

    fun deleteClient() {
        val id = clientId ?: return
        viewModelScope.launch {
            val client = clientRepository.getClient(id) ?: return@launch
            clientRepository.deleteClient(client)
            _savedEvent.emit(Unit)
        }
    }

    fun clearMessage() { userMessage.value = null }

    companion object {
        fun provideFactory(
            clientId: Long?,
            clientRepository: ClientRepository
        ): ViewModelProvider.Factory = object : ViewModelProvider.Factory {
            @Suppress("UNCHECKED_CAST")
            override fun <T : ViewModel> create(modelClass: Class<T>): T =
                AddEditClientViewModel(clientId, clientRepository) as T
        }
    }
}

package com.example.propaintersplastererspayment.feature.client.vm

import androidx.lifecycle.ViewModel
import androidx.lifecycle.ViewModelProvider
import androidx.lifecycle.viewModelScope
import com.example.propaintersplastererspayment.data.local.entity.ClientEntity
import com.example.propaintersplastererspayment.domain.repository.ClientRepository
import kotlinx.coroutines.ExperimentalCoroutinesApi
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.SharingStarted
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.combine
import kotlinx.coroutines.flow.flatMapLatest
import kotlinx.coroutines.flow.stateIn
import kotlinx.coroutines.flow.update
import kotlinx.coroutines.launch

data class ClientListUiState(
    val clients: List<ClientEntity> = emptyList(),
    val searchQuery: String = "",
    val isLoading: Boolean = true
)

@OptIn(ExperimentalCoroutinesApi::class)
class ClientListViewModel(
    private val clientRepository: ClientRepository
) : ViewModel() {

    private val searchQuery = MutableStateFlow("")

    private val filteredClients: StateFlow<List<ClientEntity>> = searchQuery
        .flatMapLatest { query ->
            if (query.isBlank()) {
                clientRepository.observeClients()
            } else {
                clientRepository.observeSuggestions(query)
            }
        }
        .stateIn(
            scope = viewModelScope,
            started = SharingStarted.WhileSubscribed(5_000),
            initialValue = emptyList()
        )

    val uiState: StateFlow<ClientListUiState> = combine(
        filteredClients,
        searchQuery
    ) { clients, query ->
        ClientListUiState(
            clients = clients,
            searchQuery = query,
            isLoading = false
        )
    }.stateIn(
        scope = viewModelScope,
        started = SharingStarted.WhileSubscribed(5_000),
        initialValue = ClientListUiState()
    )

    fun onSearchQueryChange(query: String) {
        searchQuery.update { query }
    }

    fun deleteClient(client: ClientEntity) {
        viewModelScope.launch {
            clientRepository.deleteClient(client)
        }
    }

    companion object {
        fun provideFactory(clientRepository: ClientRepository): ViewModelProvider.Factory =
            object : ViewModelProvider.Factory {
                @Suppress("UNCHECKED_CAST")
                override fun <T : ViewModel> create(modelClass: Class<T>): T =
                    ClientListViewModel(clientRepository) as T
            }
    }
}

